const input_body = $json.body ?? $json;
const mode = String(input_body.mode || "single");

let links = [];

if (mode === "batch" && Array.isArray(input_body.links)) {
  links = input_body.links
    .filter((item) => item && item.link_id && item.url)
    .map((item) => ({
      link_id: String(item.link_id),
      url: String(item.url),
      product_id: input_body.product_id ? String(input_body.product_id) : null,
      source: String(input_body.source || "supabase_radar_scheduler"),
      mode: "batch",
    }));
} else {
  if (input_body.link_id && input_body.url) {
    links = [{
      link_id: String(input_body.link_id),
      url: String(input_body.url),
      product_id: input_body.product_id ? String(input_body.product_id) : null,
      source: String(input_body.source || "supabase_radar_scheduler"),
      mode: "single",
    }];
  }
}

return links.map((item) => ({ json: item }));

const input = $json;
const html = String(input.data || "");

let url = String(input.url || "");
let link_id = String(input.link_id || "");

// Fallback: si HTTP Request no preserva campos de entrada
if (!url || !link_id) {
  try {
    const loop_json = $('Loop Over Items').item.json || {};
    url = String(loop_json.url || url || "");
    link_id = String(loop_json.link_id || link_id || "");
  } catch (e) {
    // ignore
  }
}

const shipping_words = [
  "envio", "envío", "shipping", "delivery", "transporte", "portes", "gastos de envío", "gastos de envio"
];

const normalize_number = (raw) => {
  if (!raw) return null;
  let value = String(raw).replace(/[^\d.,]/g, "").trim();
  if (!value) return null;

  if (value.includes(",") && value.includes(".")) {
    if (value.lastIndexOf(",") > value.lastIndexOf(".")) {
      value = value.replace(/\./g, "").replace(",", ".");
    } else {
      value = value.replace(/,/g, "");
    }
  } else if (value.includes(",")) {
    value = value.replace(",", ".");
  }

  const num = Number.parseFloat(value);
  return Number.isFinite(num) ? num : null;
};

const text_has_shipping = (txt) => {
  const low = String(txt || "").toLowerCase();
  return shipping_words.some((w) => low.includes(w));
};

if (!link_id) {
  return [{
    json: {
      link_id: null,
      url,
      price: null,
      error: "Missing link_id after HTTP step",
      extractor_source: null
    }
  }];
}

let price = null;
let source = null;

// 1) JSON-LD Product offers.price
try {
  const json_ld_matches = [...html.matchAll(/<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi)];
  for (const m of json_ld_matches) {
    const raw = (m[1] || "").trim();
    if (!raw) continue;

    let obj;
    try {
      obj = JSON.parse(raw);
    } catch {
      continue;
    }

    const candidates = Array.isArray(obj) ? obj : [obj];
    for (const c of candidates) {
      const offers = c && c.offers ? c.offers : null;
      const offer = Array.isArray(offers) ? offers[0] : offers;
      const p = normalize_number(offer && offer.price ? offer.price : null);
      if (p && p > 0) {
        price = p;
        source = "jsonld";
        break;
      }
    }
    if (price) break;
  }
} catch {}

// 2) Meta product price
if (!price) {
  const meta_patterns = [
    /<meta[^>]+property=["']product:price:amount["'][^>]+content=["']([^"']+)["']/i,
    /<meta[^>]+property=["']og:price:amount["'][^>]+content=["']([^"']+)["']/i,
    /<meta[^>]+itemprop=["']price["'][^>]+content=["']([^"']+)["']/i
  ];

  for (const re of meta_patterns) {
    const mm = html.match(re);
    const p = normalize_number(mm && mm[1] ? mm[1] : null);
    if (p && p > 0) {
      price = p;
      source = "meta";
      break;
    }
  }
}

// 3) Selectores típicos (regex sobre HTML)
if (!price) {
  const selector_patterns = [
    /class=["'][^"']*(?:current-price|price|our_price_display|product-price|final-price)[^"']*["'][^>]*>([\s\S]{0,120})</gi,
    /itemprop=["']price["'][^>]*content=["']([^"']+)["']/gi
  ];

  for (const re of selector_patterns) {
    const matches = [...html.matchAll(re)];
    for (const mm of matches) {
      const chunk = String(mm[1] || "");
      if (text_has_shipping(chunk)) continue;
      const p = normalize_number(chunk);
      if (p && p > 0) {
        price = p;
        source = "selector";
        break;
      }
    }
    if (price) break;
  }
}

// 4) Regex fallback con anti-shipping
if (!price) {
  const lines = html.split(/\n/).slice(0, 4000);
  for (const line of lines) {
    const low = line.toLowerCase();
    if (text_has_shipping(low)) continue;

    const m =
      line.match(/(?:€|eur)\s*([0-9]{1,5}(?:[.,][0-9]{2})?)/i) ||
      line.match(/([0-9]{1,5}(?:[.,][0-9]{2})?)\s*(?:€|eur)/i);

    if (m) {
      const p = normalize_number(m[1]);
      if (p && p > 0) {
        price = p;
        source = "regex";
        break;
      }
    }
  }
}

if (!price) {
  return [{
    json: {
      link_id,
      url,
      price: null,
      error: "Price not found",
      extractor_source: null
    }
  }];
}

return [{
  json: {
    link_id,
    url,
    price: Number(price.toFixed(2)),
    error: null,
    extractor_source: source
  }
}];

return [{
  json: {
    id: $json.id || $json.link_id || null,
    last_price: $json.last_price ?? $json.price ?? null,
    last_scraped_at: $json.last_scraped_at || new Date().toISOString(),
    status: $json.status || "active"
  }
}];

const j = item.json || {};

item.json = {
  link_id: j.link_id ? String(j.link_id) : null,
  price: (typeof j.price !== "undefined") ? j.price : null,
  error: (typeof j.error !== "undefined") ? j.error : null
};

return item;
